    kind: 'sweep',
    pathLines: [{ startMm: { xMm: 0, yMm: 0 }, endMm: { xMm: 600, yMm: 0 } }],
    profile: rectProfile(50, 50),
    profilePlane: 'normal_to_path_start',
    visibilityBinding,
  };
}

function meshCount(group: THREE.Group): number {
  let n = 0;
  group.traverse((c) => {
